const prisma = new PrismaClient({ datasources: { db: { url: DATABASE_URL_TEST } } });

// ---------------------------------------------------------------------------
// FINDING-1: AC8 — /me without bearer should return UNAUTHORIZED, not INVALID_TOKEN
//
// Spec (api-spec.yaml /me 401 example "noBearer"): code: "UNAUTHORIZED"
// Ticket AC8: "code: 'UNAUTHORIZED'"
// Implementation: routes/auth.ts line ~119 throws { code: 'INVALID_TOKEN' }
// Existing test (authRoutes.integration.test.ts:362): only asserts statusCode 401,
//   never checks the error code field — strawman test.
//
// Fix: change routes/auth.ts absent-bearer throw from INVALID_TOKEN → UNAUTHORIZED.
// ---------------------------------------------------------------------------

describe('F107a FINDING-1 — AC8 spec deviation: absent bearer on /me returns wrong code', () => {
  beforeEach(() => {
    mockVerifyBearerJwtShared.mockReset();
    mockSignInWithOtp.mockReset();
    mockSignOut.mockReset();
  });

  it('AC8 FAIL EXPECTED: GET /me without Authorization header returns 401 code UNAUTHORIZED (not INVALID_TOKEN)', async () => {
    // verifyBearerJwt is NOT called when no header — so mock state doesn't matter here
    const app = await buildApp({
      config: testConfig as unknown as import('../../config.js').Config,
      prisma,
    });

    const res = await app.inject({
      method: 'GET',
      url: '/me',
      // No authorization header — absent bearer case (AC8 scenario)
    });

    await app.close();

    expect(res.statusCode).toBe(401);
    // FAILS against current code: implementation throws { code: 'INVALID_TOKEN' } for absent bearer
    // Spec requires { code: 'UNAUTHORIZED' }
    // Fix: routes/auth.ts line ~119: change 'INVALID_TOKEN' → 'UNAUTHORIZED'
    expect(res.json().error.code).toBe('UNAUTHORIZED');
  });

  it('AC8 equivalent on /auth/logout: absent bearer returns 401 code UNAUTHORIZED', async () => {
    const app = await buildApp({
      config: testConfig as unknown as import('../../config.js').Config,
      prisma,
    });

    const res = await app.inject({
      method: 'POST',
      url: '/auth/logout',
      // No authorization header
    });

    await app.close();

    expect(res.statusCode).toBe(401);
    // Same deviation: implementation throws INVALID_TOKEN, spec implies UNAUTHORIZED for absent auth
    expect(res.json().error.code).toBe('UNAUTHORIZED');
  });
});

// ---------------------------------------------------------------------------
// FINDING-2: AC16 — 503 response MUST include Retry-After: 30 header
//
// Spec: api-spec.yaml /me 503 includes "headers: Retry-After: 30"
// Ticket AC16: "Returns HTTP 503 with Retry-After header"
// Implementation: errorHandler.ts line 729-730 sets reply.header('Retry-After', '30')
// Existing test: checks statusCode + error.code — never verifies the header.
// ---------------------------------------------------------------------------

describe('F107a FINDING-2 — AC16: 503 includes Retry-After header (missing assertion)', () => {
  beforeEach(() => {
    mockSignInWithOtp.mockReset();
    mockVerifyBearerJwtShared.mockReset();
  });

  it('AC16 via /auth/login: 503 AUTH_PROVIDER_UNAVAILABLE includes Retry-After: 30 header', async () => {
    mockSignInWithOtp.mockResolvedValue({
      data: null,
      error: { message: 'Service unavailable', status: 503 },
    });

    const app = await buildApp({
      config: testConfig as unknown as import('../../config.js').Config,
      prisma,
    });

    const res = await app.inject({
      method: 'POST',
      url: '/auth/login',
      payload: {
        provider: 'email',
        email: 'user@example.com',
        redirectTo: 'https://app.nutrixplorer.com/auth/callback',
      },
    });

    await app.close();

    expect(res.statusCode).toBe(503);
    expect(res.json().error.code).toBe('AUTH_PROVIDER_UNAVAILABLE');
    // This assertion was missing from the original AC16 test
    expect(res.headers['retry-after']).toBe('30');
  });

  it('AC16 via actorResolver: JWKS failure on bearer path returns 503 + Retry-After: 30', async () => {
    mockVerifyBearerJwtShared.mockRejectedValue(
      Object.assign(new Error('JWKS fetch failed'), { code: 'AUTH_PROVIDER_UNAVAILABLE' }),
    );

    const app = await buildApp({
      config: testConfig as unknown as import('../../config.js').Config,
      prisma,
    });

    const res = await app.inject({
      method: 'GET',
      url: '/me',
      headers: { authorization: 'Bearer eyJsomething.valid.looking' },
    });

    await app.close();

    expect(res.statusCode).toBe(503);
    expect(res.json().error.code).toBe('AUTH_PROVIDER_UNAVAILABLE');
    expect(res.headers['retry-after']).toBe('30');
  });
});

// ---------------------------------------------------------------------------
// FINDING-5: E1 — Empty Authorization string behavior characterization
//
// actorResolver.ts: `authHeader !== undefined` is true for ""
// → verifyBearerJwt("", jwksUrl) called
// → "".startsWith("Bearer ") → false → INVALID_TOKEN thrown
// → All routes return 401 for Authorization: "" (not anonymous fallback)
//
// Per RFC 6750 §3.1 this is arguably correct (malformed credentials = reject),
// but it differs from "truly absent". No test covered this before.
// ---------------------------------------------------------------------------

describe('F107a FINDING-5 — E1: empty Authorization string treated as invalid bearer', () => {
  beforeEach(() => {
    mockVerifyBearerJwtShared.mockReset();
  });

  it('E1: empty Authorization header triggers 401 (not anonymous fallback) on /estimate', async () => {
    // verifyBearerJwt called with "" → throws INVALID_TOKEN
    mockVerifyBearerJwtShared.mockRejectedValue(
      Object.assign(new Error('Authorization header must use Bearer scheme'), {
        code: 'INVALID_TOKEN',
      }),
    );

    const app = await buildApp({
      config: testConfig as unknown as import('../../config.js').Config,
      prisma,
    });

    const res = await app.inject({
      method: 'GET',
      url: '/estimate?query=arroz',
      headers: { authorization: '' }, // Empty string, NOT absent
    });

    await app.close();

    // Current behavior: 401 (bearer path triggered, even for empty string)
    // This characterizes the behavior — a client sending Authorization: "" gets 401
    expect(res.statusCode).toBe(401);
    expect(res.json().error.code).toBe('INVALID_TOKEN');
  });
});

// ---------------------------------------------------------------------------
// FINDING-6: E2 — Double-space Bearer prefix characterization
//
// "Bearer  token" passes startsWith("Bearer ") but slice(7) = " token"
// with a leading space → passed to jwtVerify as malformed JWT → INVALID_TOKEN
// This is correct behavior, but was untested.
// ---------------------------------------------------------------------------

describe('F107a FINDING-6 — E2: double-space Bearer prefix produces malformed token', () => {
  it('E2: "Bearer  token" passes startsWith but slice produces leading-space JWT', () => {
    const doubleSpace = 'Bearer  actual-token-here';
    expect(doubleSpace.startsWith('Bearer ')).toBe(true);
    const extracted = doubleSpace.slice('Bearer '.length);
    // Leading space makes it an invalid JWT string
    expect(extracted).toBe(' actual-token-here');
    expect(extracted.startsWith(' ')).toBe(true);
    // jose would receive " actual-token-here" → malformed → INVALID_TOKEN (correct)
  });
});

// ---------------------------------------------------------------------------
// FINDING-8: S2 — concurrent test weakness documentation
//
// The S2 test (authRoutes.integration.test.ts:475) fires two requests using
// ACTOR_EXT_ID_1 for BOTH parallel calls, not ACTOR_EXT_ID_1 and ACTOR_EXT_ID_2.
// This means both requests contend on the same actor upsert + same accounts upsert.
// A true concurrent test would use two different actors to test:
//   - two distinct actors both triggering accounts INSERT simultaneously
// This is MINOR — the accounts-table upsert atomicity is what matters; the actor-level
// concurrency is less critical since actor upsert is a separate operation.
// ---------------------------------------------------------------------------

describe('F107a FINDING-8 — S2 concurrent test weakness (documentation)', () => {
  it('S2 characterization: both concurrent requests in existing test use same actor ID', () => {
    // From authRoutes.integration.test.ts lines 499 + 504:
    //   req1: headers: { authorization: bearer, 'x-actor-id': ACTOR_EXT_ID_1 }
    //   req2: headers: { authorization: bearer, 'x-actor-id': ACTOR_EXT_ID_1 }
    //
    // Both use ACTOR_EXT_ID_1 — same actor, same accounts upsert.
    // A more thorough test would pair ACTOR_EXT_ID_1 + ACTOR_EXT_ID_2 to verify
    // that two different actors linking to the same account do not cause errors.
    // The accounts table constraint (UNIQUE auth_user_id) is what matters most,
    // and the existing test does cover that via the concurrent INSERT→conflict path.
    //
    // Severity: MINOR. The test is functionally valid for the DB-level upsert assertion.
    expect(true).toBe(true);
  });
});
